import { useMap } from '@vis.gl/react-maplibre';
import { inRange, throttle } from 'lodash-es';
import { useCallback, useContext, useEffect, useState } from 'react';

import { TooltipContext } from '../contexts/tooltip.context.js';

export const useGetPosition = (pinned: boolean, visible: boolean) => {
  const mapRef = useMap();
  const { markerRef } = useContext(TooltipContext);
  const getBounds = () =>
    mapRef.current?.getContainer().getBoundingClientRect();
  const [mapBounds, setMapBounds] = useState(visible ? getBounds : null);
  const updateBounds = useCallback(
    throttle(
      () => {
        setMapBounds(getBounds);
      },
      10,
      { trailing: true, leading: true },
    ),
    [],
  );

  useEffect(() => {
    if (visible) {
      updateBounds();
      return;
    }

    setMapBounds(null);
  }, [visible]);

  useEffect(() => {
    if (pinned) {
      const observers = [
        mapRef.current?.on('drag', updateBounds),
        mapRef.current?.on('zoom', updateBounds),
        mapRef.current?.on('resize', updateBounds),
      ];
      document.body.addEventListener('scroll', updateBounds, true);
      return () => {
        observers.forEach((o) => o && o.unsubscribe());
        document.body.removeEventListener('scroll', updateBounds, true);
      };
    }
  }, [pinned]);

  if (!mapBounds || !markerRef.current?._pos) {
    return;
  }
  const position = {
    x: mapBounds.x + markerRef.current?._pos.x,
    y: mapBounds.y + markerRef.current?._pos.y,
  };

  if (
    !inRange(position.x, mapBounds.left, mapBounds.right) ||
    !inRange(position.y, mapBounds.top, mapBounds.bottom)
  ) {
    return null;
  }

  return position;
};
